// Utility functions for Bullet Point Generator SDK
// Shared utilities are imported from @rezi/sdk-core

import {
  generateId as _generateId,
  debounce as _debounce,
  copyToClipboard as _copyToClipboard,
  createElement as _createElement,
  isValidEmail as _isValidEmail,
  setSessionData as _setSessionData,
  getSessionData as _getSessionData,
  setLocalData as _setLocalData,
  getLocalData as _getLocalData,
  getTodayKey as _getTodayKey,
  escapeHtml as _escapeHtml,
  truncate as _truncate,
  isClickOutside as _isClickOutside,
  getKeyboardKey as _getKeyboardKey,
  shuffleArray as _shuffleArray,
} from '@rezi/sdk-core';

export class BulletUtils {
  static generateId(prefix = 'bp'): string {
    return _generateId(prefix);
  }

  static debounce<T extends (...args: any[]) => any>(
    func: T,
    delay: number,
  ): (...args: Parameters<T>) => void {
    return _debounce(func, delay);
  }

  static copyToClipboard(text: string): Promise<boolean> {
    return _copyToClipboard(text);
  }

  static createElement<T extends HTMLElement>(
    tag: string,
    className?: string,
    attributes?: Record<string, string>,
  ): T {
    return _createElement<T>(tag, className, attributes);
  }

  // Highlight metrics in bullet points (bulletpoint-sdk specific)
  static highlightMetrics(text: string): string {
    return text.replace(/\[([^\]]+)\]/g, '<strong>[$1]</strong>');
  }

  static isValidEmail(email: string): boolean {
    return _isValidEmail(email);
  }

  static setSessionData(key: string, data: any): void {
    _setSessionData(key, data);
  }

  static getSessionData<T>(key: string): T | null {
    return _getSessionData<T>(key);
  }

  static setLocalData(key: string, data: any): void {
    _setLocalData(key, data);
  }

  static getLocalData<T>(key: string): T | null {
    return _getLocalData<T>(key);
  }

  static getTodayKey(): string {
    return _getTodayKey();
  }

  static escapeHtml(text: string): string {
    return _escapeHtml(text);
  }

  static truncate(text: string, maxLength: number): string {
    return _truncate(text, maxLength);
  }

  static isClickOutside(event: MouseEvent, element: HTMLElement): boolean {
    return _isClickOutside(event, element);
  }

  static getKeyboardKey(event: KeyboardEvent): string {
    return _getKeyboardKey(event);
  }

  static shuffleArray<T>(array: T[]): T[] {
    return _shuffleArray(array);
  }
}

// Export individual functions for convenience
export const {
  generateId,
  debounce,
  copyToClipboard,
  createElement,
  highlightMetrics,
  isValidEmail,
  setSessionData,
  getSessionData,
  setLocalData,
  getLocalData,
  getTodayKey,
  escapeHtml,
  truncate,
  isClickOutside,
  getKeyboardKey,
  shuffleArray,
} = BulletUtils;
