/**
 * BulletResults Component
 * Displays generated bullet points with copy and CTA functionality
 */

import { BulletUtils } from '../utils';
import { notify } from '../services/NotificationService';

export interface BulletResultsConfig {
  ctaUrl?: string;
  onCopy?: (bullet: string) => void;
  onCTAClick?: () => void;
}

export class BulletResults {
  private config: BulletResultsConfig;
  private container: HTMLElement | null = null;
  private resultsContainer: HTMLElement | null = null;
  private emptyState: HTMLElement | null = null;
  private loadingState: HTMLElement | null = null;
  private copiedBulletIndex: number | null = null;

  constructor(config: BulletResultsConfig) {
    this.config = config;
  }

  render(): HTMLElement {
    const panel = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-panel rbp-bullet-points',
    );

    // Header
    const header = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-panel-header',
    );
    const headerIcon = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-header-icon',
    );
    headerIcon.innerHTML = '<i class="fa-duotone fa-solid fa-sparkles"></i>';
    const headerTitle = BulletUtils.createElement<HTMLHeadingElement>(
      'h2',
      'rbp-panel-title',
    );
    headerTitle.textContent = 'Bullet Points';
    header.appendChild(headerIcon);
    header.appendChild(headerTitle);
    panel.appendChild(header);

    // Empty state (initial)
    this.emptyState = this.createEmptyState();
    panel.appendChild(this.emptyState);

    // Loading state (hidden)
    this.loadingState = this.createLoadingState();
    this.loadingState.style.display = 'none';
    panel.appendChild(this.loadingState);

    // Results container (hidden)
    this.resultsContainer = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-results-container',
    );
    this.resultsContainer.style.display = 'none';
    panel.appendChild(this.resultsContainer);

    this.container = panel;
    return panel;
  }

  private createEmptyState(): HTMLElement {
    const empty = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-empty-state',
    );
    const icon = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-empty-icon',
    );
    icon.innerHTML = '<i class="fa-duotone fa-solid fa-list-ul"></i>';
    const text = BulletUtils.createElement<HTMLParagraphElement>(
      'p',
      'rbp-empty-text',
    );
    text.textContent =
      'Enter your role details and select skills to generate tailored bullet points.';

    empty.appendChild(icon);
    empty.appendChild(text);
    return empty;
  }

  private createLoadingState(): HTMLElement {
    const loading = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-loading-state',
    );
    for (let i = 0; i < 15; i++) {
      const skeleton = BulletUtils.createElement<HTMLDivElement>(
        'div',
        'rbp-skeleton',
      );
      const line1 = BulletUtils.createElement<HTMLDivElement>(
        'div',
        'rbp-skeleton-line',
      );
      const line2 = BulletUtils.createElement<HTMLDivElement>(
        'div',
        'rbp-skeleton-line',
      );
      skeleton.appendChild(line1);
      skeleton.appendChild(line2);
      loading.appendChild(skeleton);
    }
    return loading;
  }

  showLoading(): void {
    if (this.emptyState) this.emptyState.style.display = 'none';
    if (this.resultsContainer) this.resultsContainer.style.display = 'none';
    if (this.loadingState) this.loadingState.style.display = 'flex';
  }

  showResults(bullets: string[]): void {
    if (!this.resultsContainer) return;

    // Hide loading and empty states
    if (this.loadingState) this.loadingState.style.display = 'none';
    if (this.emptyState) this.emptyState.style.display = 'none';

    // Clear and populate results
    this.resultsContainer.innerHTML = '';
    this.resultsContainer.style.display = 'flex';

    // Create bullet items
    const bulletsList = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-bullets-list',
    );

    bullets.forEach((bullet, index) => {
      const item = this.createBulletItem(bullet, index);
      bulletsList.appendChild(item);
    });

    this.resultsContainer.appendChild(bulletsList);

    // Add CTA button
    const ctaButton = BulletUtils.createElement<HTMLButtonElement>(
      'button',
      'rbp-button',
    );
    ctaButton.textContent = 'BUILD A FULL RESUME WITH THESE BULLET POINTS';
    ctaButton.addEventListener('click', () => this.handleCTAClick());
    this.resultsContainer.appendChild(ctaButton);
  }

  private createBulletItem(bullet: string, index: number): HTMLElement {
    const item = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-bullet-item',
    );

    const bulletText = BulletUtils.createElement<HTMLParagraphElement>(
      'p',
      'rbp-bullet-text',
    );
    bulletText.innerHTML = BulletUtils.escapeHtml(bullet);
    item.appendChild(bulletText);

    const copyBtn = BulletUtils.createElement<HTMLButtonElement>(
      'button',
      'rbp-copy-btn',
    );
    copyBtn.innerHTML = '<i class="fa-duotone fa-solid fa-copy"></i>';
    copyBtn.dataset['index'] = index.toString();

    copyBtn.addEventListener('click', () =>
      this.handleCopy(bullet, index, copyBtn),
    );

    item.appendChild(copyBtn);
    return item;
  }

  private async handleCopy(
    bullet: string,
    index: number,
    button: HTMLButtonElement,
  ): Promise<void> {
    try {
      await navigator.clipboard.writeText(bullet);

      // Show success notification
      notify.success('Copied bullet point', 2000);

      // Update button state temporarily
      this.copiedBulletIndex = index;
      button.innerHTML = '<i class="fa-duotone fa-solid fa-check"></i>';
      button.classList.add('rbp-copied');

      setTimeout(() => {
        button.innerHTML = '<i class="fa-duotone fa-solid fa-copy"></i>';
        button.classList.remove('rbp-copied');
        if (this.copiedBulletIndex === index) {
          this.copiedBulletIndex = null;
        }
      }, 2000);

      if (this.config.onCopy) {
        this.config.onCopy(bullet);
      }
    } catch (error) {
      console.error('Failed to copy to clipboard:', error);
      notify.error('Failed to copy', 2000);
      button.innerHTML = '<i class="fa-duotone fa-solid fa-times"></i>';
      setTimeout(() => {
        button.innerHTML = '<i class="fa-duotone fa-solid fa-copy"></i>';
      }, 2000);
    }
  }

  private handleCTAClick(): void {
    if (this.config.onCTAClick) {
      this.config.onCTAClick();
    }

    // Redirect if URL is provided
    if (this.config.ctaUrl) {
      window.location.href = this.config.ctaUrl;
    }
  }

  showEmpty(): void {
    if (this.loadingState) this.loadingState.style.display = 'none';
    if (this.resultsContainer) this.resultsContainer.style.display = 'none';
    if (this.emptyState) this.emptyState.style.display = 'flex';
  }

  clear(): void {
    if (this.resultsContainer) {
      this.resultsContainer.innerHTML = '';
      this.resultsContainer.style.display = 'none';
    }
    this.showEmpty();
  }
}
