/**
 * RecaptchaService - reCAPTCHA Enterprise integration
 * Loads the reCAPTCHA Enterprise script dynamically and generates tokens.
 * Follows the same pattern as the existing React app (grecaptcha.enterprise.execute + X-Recaptcha header).
 * Graceful degradation: returns null on any failure so API calls proceed without a token.
 */

declare global {
  interface Window {
    grecaptcha?: {
      enterprise: {
        ready: (cb: () => void) => void;
        execute: (
          siteKey: string,
          options: { action: string },
        ) => Promise<string>;
      };
    };
  }
}

export class RecaptchaService {
  private siteKey: string;
  private scriptLoaded: Promise<boolean> | null = null;

  constructor(siteKey: string) {
    this.siteKey = siteKey;
  }

  /**
   * Load the reCAPTCHA Enterprise script. Safe to call multiple times — only loads once.
   */
  loadScript(): Promise<boolean> {
    if (this.scriptLoaded) {
      return this.scriptLoaded;
    }

    this.scriptLoaded = new Promise<boolean>((resolve) => {
      // Already loaded by the host page
      if (window.grecaptcha?.enterprise) {
        window.grecaptcha.enterprise.ready(() => resolve(true));
        return;
      }

      const script = document.createElement('script');
      script.src = `https://www.google.com/recaptcha/enterprise.js?render=${this.siteKey}`;
      script.async = true;

      script.onload = () => {
        if (window.grecaptcha?.enterprise) {
          window.grecaptcha.enterprise.ready(() => resolve(true));
        } else {
          resolve(false);
        }
      };

      script.onerror = () => {
        this.scriptLoaded = null; // 실패 시 초기화하여 재시도 가능하게
        resolve(false);
      };

      document.head.appendChild(script);
    });

    return this.scriptLoaded;
  }

  /**
   * Generate a reCAPTCHA token for the given action.
   * Returns null if the script isn't loaded or execution fails.
   */
  async getToken(action: string): Promise<string | null> {
    try {
      const loaded = await this.loadScript();
      if (!loaded || !window.grecaptcha?.enterprise) {
        return null;
      }

      return await window.grecaptcha.enterprise.execute(this.siteKey, {
        action,
      });
    } catch {
      return null;
    }
  }
}
