/**
 * SkillSelector Component
 * Handles skill selection with chip-based UI and custom skill input
 */

import { BulletUtils } from '../utils';
import { Skill } from '../types';

export interface SkillSelectorConfig {
  maxSkills: number;
  onSkillsChange: (skills: Skill[]) => void;
}

export class SkillSelector {
  private config: SkillSelectorConfig;
  private container: HTMLElement | null = null;
  private header: HTMLElement | null = null;
  private skillsCloud: HTMLElement | null = null;
  private customInput: HTMLInputElement | null = null;
  private inputWrapper: HTMLElement | null = null;
  private availableSkills: Skill[] = [];
  private selectedSkills: Skill[] = [];
  private customSkills: Skill[] = [];

  constructor(config: SkillSelectorConfig) {
    this.config = config;
  }

  render(): HTMLElement {
    this.container = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-content-wrapper',
    );
    this.container.style.display = 'none';
    return this.container;
  }

  showLoading(): void {
    if (!this.container) return;

    this.container.innerHTML = '';
    this.container.style.display = 'flex';

    // Header
    this.header = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-panel-header',
    );
    const icon = BulletUtils.createElement<HTMLSpanElement>(
      'span',
      'rbp-header-icon',
    );
    icon.innerHTML =
      '<i class="fa-duotone fa-solid fa-clipboard-list-check"></i>';
    const title = BulletUtils.createElement<HTMLSpanElement>(
      'span',
      'rbp-panel-title',
    );
    title.textContent = `Select Skills (0/${this.config.maxSkills})`;
    this.header.appendChild(icon);
    this.header.appendChild(title);
    this.container.appendChild(this.header);

    // Skeleton chips cloud
    const skeletonCloud = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-skills-cloud-skeleton',
    );
    const widths = [72, 96, 60, 112, 80, 88, 68, 104, 76, 92, 64, 84];
    widths.forEach((w) => {
      const chip = BulletUtils.createElement<HTMLSpanElement>(
        'span',
        'rbp-skill-chip-skeleton',
      );
      chip.style.width = `${w}px`;
      skeletonCloud.appendChild(chip);
    });
    this.container.appendChild(skeletonCloud);
  }

  show(skills: Skill[]): void {
    if (!this.container) return;

    this.availableSkills = skills;
    this.container.innerHTML = '';
    this.container.style.display = 'flex';

    // Header
    this.header = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-panel-header',
    );
    const icon = BulletUtils.createElement<HTMLSpanElement>(
      'span',
      'rbp-header-icon',
    );
    icon.innerHTML =
      '<i class="fa-duotone fa-solid fa-clipboard-list-check"></i>';
    const title = BulletUtils.createElement<HTMLSpanElement>(
      'span',
      'rbp-panel-title',
    );
    title.textContent = `Select Skills (${this.selectedSkills.length}/${this.config.maxSkills})`;
    this.header.appendChild(icon);
    this.header.appendChild(title);
    this.container.appendChild(this.header);

    // Skills cloud — API skills + previously typed custom skills
    this.skillsCloud = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-skills-cloud',
    );

    this.availableSkills.forEach((skill) => {
      const chip = this.createSkillChip(skill);
      this.skillsCloud?.appendChild(chip);
    });

    // Re-render any custom skills typed before job title change (edge case)
    this.customSkills.forEach((skill) => {
      const chip = this.createSkillChip(skill);
      this.skillsCloud?.appendChild(chip);
    });

    this.container.appendChild(this.skillsCloud);

    // Custom skill input area
    this.renderCustomInput();
  }

  hide(): void {
    if (this.container) {
      this.container.style.display = 'none';
    }
    // Clear when job title changes
    this.customSkills = [];
    this.selectedSkills = [];
  }

  private createSkillChip(skill: Skill): HTMLElement {
    const chip = BulletUtils.createElement<HTMLButtonElement>(
      'button',
      'rbp-skill-chip',
    );
    chip.textContent = skill.name;
    chip.dataset['skillId'] = skill.id;

    const isSelected = this.selectedSkills.some((s) => s.id === skill.id);
    if (isSelected) {
      chip.classList.add('rbp-selected');
    }

    chip.addEventListener('click', () => {
      this.toggleSkill(skill);
    });

    return chip;
  }

  /**
   * Render the custom skill text input area — same UI as JobTitleInput
   */
  private renderCustomInput(): void {
    if (!this.container) return;

    const group = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-input-group',
    );

    const label = BulletUtils.createElement<HTMLLabelElement>(
      'label',
      'rbp-input-label',
    );
    label.textContent = 'ADD SKILLS';
    group.appendChild(label);

    this.inputWrapper = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-input-wrapper',
    );

    this.customInput = BulletUtils.createElement<HTMLInputElement>(
      'input',
      'rbp-input',
    );
    this.customInput.type = 'text';
    this.customInput.placeholder = 'e.g. React, Python, Git...';
    this.customInput.maxLength = 50;

    this.customInput.addEventListener('keydown', (e: KeyboardEvent) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        this.addCustomSkill();
      }
    });

    this.inputWrapper.appendChild(this.customInput);
    group.appendChild(this.inputWrapper);
    this.container.appendChild(group);

    this.updateCustomInputState();
  }

  /**
   * Validate and add a typed skill as a regular chip in skillsCloud
   */
  private addCustomSkill(): void {
    if (!this.customInput) return;

    const rawValue = this.customInput.value.trim();

    // Validation: minimum length
    if (rawValue.length < 2) return;

    // Validation: check max skills limit
    if (this.selectedSkills.length >= this.config.maxSkills) return;

    // Normalize: capitalize first letter
    const skillName = rawValue.charAt(0).toUpperCase() + rawValue.slice(1);

    // Duplicate check against all available + custom skills
    const isDuplicateInAvailable = this.availableSkills.some(
      (s) => s.name.toLowerCase() === skillName.toLowerCase(),
    );
    const isDuplicateInCustom = this.customSkills.some(
      (s) => s.name.toLowerCase() === skillName.toLowerCase(),
    );

    if (isDuplicateInAvailable || isDuplicateInCustom) {
      // Auto-select if it exists in available skills
      if (isDuplicateInAvailable) {
        const existingSkill = this.availableSkills.find(
          (s) => s.name.toLowerCase() === skillName.toLowerCase(),
        );
        if (
          existingSkill &&
          !this.selectedSkills.some((s) => s.id === existingSkill.id)
        ) {
          this.toggleSkill(existingSkill);
        }
      }
      this.customInput.value = '';
      return;
    }

    // Create new skill
    const newSkill: Skill = {
      id: `custom-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
      name: skillName,
      isCustom: true,
    };

    // Track for dedup and re-render
    this.customSkills.push(newSkill);
    this.availableSkills.push(newSkill);

    // Auto-select
    this.selectedSkills.push(newSkill);

    // Add as regular chip to skillsCloud
    if (this.skillsCloud) {
      const chip = this.createSkillChip(newSkill);
      chip.classList.add('selected');
      this.skillsCloud.appendChild(chip);
    }

    // Clear input
    this.customInput.value = '';

    this.updateUI();
    this.updateCustomInputState();
    this.config.onSkillsChange(this.selectedSkills);
  }

  /**
   * Enable/disable the custom input based on max skills reached
   */
  private updateCustomInputState(): void {
    if (!this.customInput) return;

    const isMaxReached = this.selectedSkills.length >= this.config.maxSkills;

    this.customInput.disabled = isMaxReached;

    if (isMaxReached) {
      this.customInput.placeholder = `Maximum ${this.config.maxSkills} skills selected`;
    } else {
      this.customInput.placeholder = 'Type a skill and press Enter';
    }
  }

  private toggleSkill(skill: Skill): void {
    const index = this.selectedSkills.findIndex((s) => s.id === skill.id);

    if (index > -1) {
      // Deselect
      this.selectedSkills.splice(index, 1);
    } else {
      // Select (if under max)
      if (this.selectedSkills.length < this.config.maxSkills) {
        this.selectedSkills.push(skill);
      } else {
        return; // Max reached
      }
    }

    this.updateUI();
    this.updateCustomInputState();
    this.config.onSkillsChange(this.selectedSkills);
  }

  private updateUI(): void {
    // Update header count
    if (this.header) {
      const title = this.header.querySelector('.rbp-panel-title');
      if (title) {
        title.textContent = `Select Skills (${this.selectedSkills.length}/${this.config.maxSkills})`;
      }
    }

    // Update all chip states in skillsCloud
    if (this.skillsCloud) {
      const chips = this.skillsCloud.querySelectorAll('.rbp-skill-chip');
      chips.forEach((chip) => {
        const skillId = (chip as HTMLElement).dataset['skillId'];
        const isSelected = this.selectedSkills.some((s) => s.id === skillId);

        if (isSelected) {
          chip.classList.add('rbp-selected');
        } else {
          chip.classList.remove('rbp-selected');
        }
      });
    }

    this.updateCustomInputState();
  }

  getSelectedSkills(): Skill[] {
    return this.selectedSkills;
  }

  setSelectedSkills(skills: Skill[]): void {
    this.selectedSkills = skills;
    this.updateUI();
  }

  clearSelection(): void {
    this.selectedSkills = [];
    this.customSkills = [];
    this.updateUI();
  }

  isVisible(): boolean {
    return this.container?.style.display !== 'none';
  }

  disableUnselected(): void {
    if (this.skillsCloud) {
      const chips = this.skillsCloud.querySelectorAll('.rbp-skill-chip');
      chips.forEach((chip) => {
        const skillId = (chip as HTMLElement).dataset['skillId'];
        const isSelected = this.selectedSkills.some((s) => s.id === skillId);
        if (!isSelected) {
          (chip as HTMLButtonElement).disabled = true;
        }
      });
    }

    if (this.customInput) this.customInput.disabled = true;
  }

  enableAll(): void {
    if (this.skillsCloud) {
      const chips = this.skillsCloud.querySelectorAll('.rbp-skill-chip');
      chips.forEach((chip) => {
        (chip as HTMLButtonElement).disabled = false;
      });
    }

    this.updateCustomInputState();
  }
}
