/**
 * BulletPointGenerator - Main Orchestrator
 * Coordinates all sub-components and manages application state
 */

import {
  BulletPointConfig,
  WidgetState,
  Skill,
  ExperienceLevel,
  DEFAULT_MAX_SKILLS,
} from '../types';
import { BulletUtils } from '../utils';
import { notify } from '../services/NotificationService';
import { SkillSuggester, BulletGenerator, RecaptchaService } from '../services';
import { getRecaptchaSiteKey } from '../config/api';
import { JobTitleInput } from './JobTitleInput';
import { ExperienceSelector } from './ExperienceSelector';
import { SkillSelector } from './SkillSelector';
import { BulletResults } from './BulletResults';

export class BulletPointGenerator {
  private config: BulletPointConfig;
  private state: WidgetState;
  private container: HTMLElement | null = null;
  private skillSuggester: SkillSuggester;
  private bulletGenerator: BulletGenerator;

  // Sub-components
  private jobTitleInput: JobTitleInput;
  private experienceSelector: ExperienceSelector;
  private skillSelector: SkillSelector;
  private bulletResults: BulletResults;

  // DOM elements
  private generateButton: HTMLButtonElement | null = null;

  // Debounced skill loader (500ms)
  private debouncedLoadSkills: (title: string) => void;

  constructor(config: BulletPointConfig) {
    this.config = {
      maxSkillSelection: DEFAULT_MAX_SKILLS,
      ...config,
    };

    // Initialize reCAPTCHA (dev/prod use different site keys)
    const siteKey =
      this.config.recaptchaSiteKey ??
      getRecaptchaSiteKey(this.config.isDev || false);
    let recaptchaService: RecaptchaService | undefined;
    if (siteKey) {
      recaptchaService = new RecaptchaService(siteKey);
      recaptchaService.loadScript();
    }

    // Initialize services
    this.skillSuggester = new SkillSuggester(
      this.config.isDev || false,
      recaptchaService,
    );
    this.bulletGenerator = new BulletGenerator(
      this.config.isDev || false,
      true,
      recaptchaService,
    );

    // Initialize state
    this.state = {
      phase: 'input',
      jobTitle: '',
      experienceLevel: null,
      availableSkills: [],
      selectedSkills: [],
      generatedBullets: [],
      isAutocompleteOpen: false,
      isExperienceDropdownOpen: false,
      copiedBulletIndex: null,
      error: null,
    };

    // Initialize sub-components
    this.jobTitleInput = new JobTitleInput({
      placeholder: 'e.g., Product Manager',
      onTitleChange: (title) => this.handleJobTitleChange(title),
    });

    this.experienceSelector = new ExperienceSelector({
      onLevelChange: (level) => this.handleExperienceLevelChange(level),
    });

    this.skillSelector = new SkillSelector({
      maxSkills: this.config.maxSkillSelection || DEFAULT_MAX_SKILLS,
      onSkillsChange: (skills) => this.handleSkillsChange(skills),
    });

    this.bulletResults = new BulletResults({
      ctaUrl: this.config.ctaUrl,
      onCopy: (bullet) => this.handleCopy(bullet),
      onCTAClick: () => this.handleCTAClick(),
    });

    this.debouncedLoadSkills = BulletUtils.debounce(
      (title: string) => this.loadSkills(title),
      800,
    );

    this.initialize();
  }

  // Initialization
  private initialize(): void {
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', () => this.render());
    } else {
      this.render();
    }
  }

  // Main render
  private render(): void {
    this.container = document.querySelector(this.config.containerSelector);

    if (!this.container) {
      console.warn(
        `BulletPointGenerator: No element found with selector "${this.config.containerSelector}"`,
      );
      return;
    }

    // Clear container
    this.container.innerHTML = '';
    this.container.className = 'rbp-generator';

    // Create 2-column layout
    const wrapper = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-wrapper',
    );

    // Left panel: Role Details
    const roleDetailsPanel = this.createRoleDetailsPanel();
    wrapper.appendChild(roleDetailsPanel);

    // Right panel: Bullet Points
    const bulletPointsPanel = this.bulletResults.render();
    wrapper.appendChild(bulletPointsPanel);

    this.container.appendChild(wrapper);
  }

  // Create Role Details Panel (Left)
  private createRoleDetailsPanel(): HTMLElement {
    const panel = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-panel rbp-role-details',
    );
    const roleWrapper = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-content-wrapper',
    );

    // Header
    const header = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-panel-header',
    );
    const headerIcon = BulletUtils.createElement<HTMLDivElement>(
      'div',
      'rbp-header-icon',
    );
    headerIcon.innerHTML = '<i class="fa-duotone fa-solid fa-id-badge"></i>';
    const headerTitle = BulletUtils.createElement<HTMLHeadingElement>(
      'h2',
      'rbp-panel-title',
    );
    headerTitle.textContent = 'Role Details';
    header.appendChild(headerIcon);
    header.appendChild(headerTitle);
    roleWrapper.appendChild(header);

    // Job Title Input
    const jobTitleGroup = this.jobTitleInput.render();
    roleWrapper.appendChild(jobTitleGroup);

    // Experience Select
    const experienceGroup = this.experienceSelector.render();
    roleWrapper.appendChild(experienceGroup);
    panel.appendChild(roleWrapper);

    // Skills Section
    const skillsSection = this.skillSelector.render();
    panel.appendChild(skillsSection);
    // Generate Button
    this.generateButton = BulletUtils.createElement<HTMLButtonElement>(
      'button',
      'rbp-button',
    );
    this.generateButton.disabled = true;
    this.generateButton.innerHTML = `<i class="fa-duotone fa-solid fa-sparkles"></i> GENERATE BULLET POINTS`;
    this.generateButton.addEventListener('click', () => this.handleGenerate());
    panel.appendChild(this.generateButton);

    return panel;
  }

  // Event Handlers
  private handleJobTitleChange(title: string): void {
    this.setState({ jobTitle: title });

    if (this.config.onJobTitleChange) {
      this.config.onJobTitleChange(title);
    }

    // Load skills if title is not empty (debounced)
    if (title.trim().length > 2) {
      this.debouncedLoadSkills(title);
    } else {
      this.skillSelector.hide();
    }

    this.updateGenerateButton();
  }

  private handleExperienceLevelChange(level: ExperienceLevel): void {
    this.setState({ experienceLevel: level });
    this.updateGenerateButton();
  }

  private handleSkillsChange(skills: Skill[]): void {
    this.setState({ selectedSkills: skills });
    this.updateGenerateButton();
  }

  private handleCopy(bullet: string): void {
    if (this.config.onCopy) {
      this.config.onCopy(bullet);
    }
  }

  private handleCTAClick(): void {
    if (this.config.onCTAClick) {
      this.config.onCTAClick(this.state.generatedBullets, this.state.jobTitle);
    }

    // Store data in localStorage so it persists across tabs and sessions
    const data = {
      jobTitle: this.state.jobTitle,
      experienceLevel: this.state.experienceLevel,
      selectedSkills: this.state.selectedSkills.map((s) => s.name),
      bullets: this.state.generatedBullets,
    };

    try {
      localStorage.setItem('rezi_bullet_data', JSON.stringify(data));
    } catch (error) {
      console.error('Failed to store data in localStorage:', error);
    }
  }

  private async loadSkills(jobTitle: string): Promise<void> {
    this.skillSelector.showLoading();

    // getSuggestedSkills() never throws — handles fallback internally
    const result = await this.skillSuggester.getSuggestedSkills(jobTitle);

    this.setState({ availableSkills: result.skills, selectedSkills: [] });
    this.skillSelector.show(result.skills);
    this.skillSelector.clearSelection();
    this.skillSelector.enableAll();

    if (this.config.onSkillsLoaded) {
      this.config.onSkillsLoaded(result.skills);
    }
  }

  private async handleGenerate(): Promise<void> {
    this.setState({ phase: 'loading' });
    this.bulletResults.showLoading();

    try {
      const result = await this.bulletGenerator.generateBullets({
        jobTitle: this.state.jobTitle,
        experienceLevel: this.state.experienceLevel!,
        selectedSkills: this.state.selectedSkills,
      });

      if (result.error === 'rate_limit') {
        notify.error(
          'Daily limit reached. Sign up for unlimited access!',
          5000,
        );
        this.setState({ phase: 'input', error: 'rate_limit' });
        this.bulletResults.showEmpty();

        // Redirect to sign up page
        const ctaUrl = this.config.ctaUrl;
        if (ctaUrl) {
          setTimeout(() => {
            window.location.href = ctaUrl;
          }, 2000);
        }
        return;
      }

      if (result.error === 'api_error' || result.bullets.length === 0) {
        notify.error(
          'Failed to generate bullet points. Please try again.',
          3000,
        );
        this.setState({ phase: 'input', error: 'api_error' });
        this.bulletResults.showEmpty();
        return;
      }

      this.setState({
        phase: 'results',
        generatedBullets: result.bullets,
      });

      this.bulletResults.showResults(result.bullets);

      // Disable unselected skills after generation
      this.skillSelector.disableUnselected();

      if (this.config.onGenerate) {
        this.config.onGenerate(result.bullets);
      }
    } catch (error) {
      console.error(
        '[BulletPointGenerator] Failed to generate bullets:',
        error,
      );
      notify.error('Something went wrong. Please try again.', 3000);
      this.setState({ phase: 'input', error: 'api_error' });
      this.bulletResults.showEmpty();

      if (this.config.onError) {
        this.config.onError(error as Error);
      }
    }
  }

  private updateGenerateButton(): void {
    if (!this.generateButton) return;

    const canGenerate =
      this.state.jobTitle.trim().length > 0 &&
      this.state.experienceLevel !== null &&
      this.state.selectedSkills.length > 0;

    this.generateButton.disabled = !canGenerate;
  }

  // State management
  private setState(updates: Partial<WidgetState>): void {
    this.state = { ...this.state, ...updates };
  }

  // Public API
  public getState(): WidgetState {
    return { ...this.state };
  }

  public destroy(): void {
    if (this.container) {
      this.container.innerHTML = '';
    }
  }
}
